@lp.for_each_kernel
def replace_nan_with_pymbolic_nan(kernel: lp.LoopKernel) -> lp.LoopKernel:
    from constantdict import constantdict
    from loopy.symbolic import SubstitutionMapper
    from pymbolic.mapper.substitutor import make_subst_func

    mapper = SubstitutionMapper(make_subst_func({"NaN": NaN()}))
    return kernel.copy(
        instructions=tuple(
            insn.with_transformed_expressions(mapper) for insn in kernel.instructions
        ),
        substitutions=constantdict(
            {
                subst_name: subst.copy(expression=mapper(subst.expression))
                for subst_name, subst in kernel.substitutions.items()
            }
        ),
    )


