def get_random_ary(rng, shape: tuple[int, ...], dtype: lp.NumpyType):
    from pytools import product

    dtype = dtype.numpy_dtype
    if dtype == np.uint64 or dtype == np.uint32:
        return np.arange(product(shape), dtype=dtype).reshape(shape)
    elif dtype == np.int8:
        return np.zeros(shape, dtype)
    elif dtype == np.float64:
        return rng.random(shape)
    else:
        raise NotImplementedError(dtype)


def get_params_for_euler_facemass() -> Mapping[str, np.ndarray[np.dtype[Any]]]:
    from grudge.models.euler import ConservedEulerField
    from meshmode.dof_array import array_context_for_pickling
    actx = NumpyArrayContext()
    t_unit = get_euler_facemass_kernel()
    with (
        open(
            get_benchmark_ref_input_arguments_path("euler", 3, 3), "rb"
        ) as fp,
        array_context_for_pickling(actx),
    ):
        loaded = cast("tuple[tuple[Any, ...], dict[str, Any]]", pickle.load(fp))
        (_, conserved_field), np_kwargs = loaded
        assert not np_kwargs
        assert isinstance(conserved_field, ConservedEulerField)

    literals = np.load("euler_literals.npy", allow_pickle=True).item()
    return {
        "mass": conserved_field.mass[0],
        "energy": conserved_field.energy[0],
        "momentum_0": conserved_field.momentum[0][0],
        "momentum_1": conserved_field.momentum[1][0],
        "momentum_2": conserved_field.momentum[2][0],
        **{
            name: literals[name]
            for name in t_unit.default_entrypoint.arg_dict
            if name.startswith("_pt_data")
        },
    }
